  --primary-foreground: oklch(0.9460 0.0124 91.5205);
  --secondary: oklch(0.4814 0.1311 252.4856);
  --secondary-foreground: oklch(1.0000 0 0);
  --muted: oklch(0.9477 0.0108 158.8408);
  --muted-foreground: oklch(0.4833 0.0410 160.9726);
  --accent: oklch(0.6521 0.1322 81.5716);
  --accent-foreground: oklch(1.0000 0 0);
  --destructive: oklch(0.5771 0.2152 27.3250);
  --destructive-foreground: oklch(1.0000 0 0);
  --border: oklch(0.8776 0.0344 157.5587);
  --input: oklch(0.8776 0.0344 157.5587);
  --ring: oklch(0.3548 0.0574 161.2793);
  --chart-1: oklch(0.3548 0.0574 161.2793);
  --chart-2: oklch(0.4814 0.1311 252.4856);
  --chart-3: oklch(0.6521 0.1322 81.5716);
  --chart-4: oklch(0.7647 0.1149 168.3351);
  --chart-5: oklch(0.6232 0.1486 251.5031);
  --sidebar: oklch(0.3548 0.0574 161.2793);
  --sidebar-foreground: oklch(0.9460 0.0124 91.5205);
  --sidebar-primary: oklch(0.6521 0.1322 81.5716);
  --sidebar-primary-foreground: oklch(0.3548 0.0574 161.2793);
  --sidebar-accent: oklch(1.0000 0 0);
  --sidebar-accent-foreground: oklch(0.3548 0.0574 161.2793);
  --sidebar-border: oklch(0.4548 0.0723 160.5915);
  --sidebar-ring: oklch(0.6521 0.1322 81.5716);
